import os,json,boto3,urllib.request,urllib.error
from datetime import datetime,timezone
SB_URL=os.environ["SUPABASE_URL"];SB_KEY=os.environ["SUPABASE_SERVICE_ROLE_KEY"];EB=os.environ["EVENT_BUS_NAME"]
eb=boto3.client("events",region_name="ap-southeast-2")
def sb(m,p,d=None):
    req=urllib.request.Request(f"{SB_URL}/rest/v1/{p}",data=json.dumps(d).encode() if d else None,method=m)
    req.add_header("apikey",SB_KEY);req.add_header("Authorization",f"Bearer {SB_KEY}")
    req.add_header("Content-Type","application/json");req.add_header("Prefer","return=representation")
    with urllib.request.urlopen(req) as r: return json.loads(r.read())
def now(): return datetime.now(timezone.utc).isoformat()
def lambda_handler(event,context):
    sites=sb("GET","ops_site_registry?select=id,slug,canonical_url,vercel_url,github_repo,health_status&status=eq.LIVE") or []
    violations=[]
    for site in sites:
        slug=site.get("slug","?");health="UNKNOWN";url=site.get("canonical_url") or site.get("vercel_url")
        if url:
            try:
                req=urllib.request.Request(url,method="HEAD");req.add_header("User-Agent","t4h/1.0")
                with urllib.request.urlopen(req,timeout=8) as r: health="UP" if r.status<400 else "DOWN"
            except: health="DOWN"
        sb("PATCH",f"ops_site_registry?id=eq.{site['id']}",{"health_status":health,"last_checked":now()})
        codes=[]
        if not site.get("github_repo"): codes.append("NO_GITHUB")
        if not site.get("canonical_url"): codes.append("NO_PUBLIC")
        if not site.get("vercel_url"): codes.append("NO_DEPLOY")
        if health in("DOWN","DEGRADED"): codes.append(f"HEALTH_{health}")
        for code in codes:
            eb.put_events(Entries=[{"Source":"t4h.control-tower","DetailType":"SiteViolationDetected","Detail":json.dumps({"site_id":site["id"],"slug":slug,"violation_code":code}),"EventBusName":EB}])
            violations.append({"slug":slug,"code":code})
    return {"scanned":len(sites),"violations":len(violations)}
